chapterList.requestInfo:
@js:
var tocUrl=params.queryInfo.tocUrl||params.queryInfo.detailUrl||params.queryInfo.url||result;
if(!tocUrl)return"";
var m=tocUrl.match(/Html\/(\d+)\/(\d+)\//);
var cid=m?m[1]:"";
var bid=m?m[2]:"";
params.cid=cid;
params.bid=bid;
return{"url":tocUrl,"httpHeaders":config.httpHeaders};
